import numpy as np
import collections.abc

def is_array_like(obj):
    """Check if object can be converted to a numpy array."""
    # Exclude strings and bytes
    if isinstance(obj, (str, bytes)):
        return False
    # Check if it's a numpy array
    if isinstance(obj, np.ndarray):
        return True
    # Check if it's a sequence (list, tuple, range, etc.)
    if isinstance(obj, collections.abc.Sequence):
        return True
    return False

def convert_to_array(obj):
    """Convert array-like object to numpy array."""
    if isinstance(obj, np.ndarray):
        return obj
    return np.asarray(obj)

# Test cases
test_cases = [
    ([0, 1], True),
    ((0, 1), True),
    (range(2), True),
    (np.array([0, 1]), True),
    ("string", False),
    (b"bytes", False),
    (123, False),  # scalar
    ({"key": "value"}, False),  # dict
]

for obj, expected in test_cases:
    result = is_array_like(obj)
    status = "✓" if result == expected else "✗"
    print(f"{status} is_array_like({obj!r}) = {result}, expected {expected}")

    if result:
        try:
            arr = convert_to_array(obj)
            print(f"  -> convert_to_array: shape={arr.shape}, dtype={arr.dtype}")
        except Exception as e:
            print(f"  -> convert_to_array failed: {e}")
EOF

