import sys

# Read the file
with open('pyvista/core/grid.py', 'r') as f:
    lines = f.readlines()

# Find where to add collections.abc import
import_line_index = None
for i, line in enumerate(lines):
    if line.strip() == 'import warnings':
        import_line_index = i
        break

# Add collections.abc import after warnings
if import_line_index is not None:
    lines.insert(import_line_index + 1, 'import collections.abc\n')

# Now find the RectilinearGrid __init__ method
init_start = None
for i, line in enumerate(lines):
    if 'class RectilinearGrid(' in line:
        # Find the __init__ method within this class
        for j in range(i, min(i + 50, len(lines))):
            if 'def __init__' in lines[j]:
                init_start = j
                break
        if init_start:
            break

if init_start:
    # Find the end of the __init__ method (look for next def or class at same indentation)
    init_end = None
    init_indent = len(lines[init_start]) - len(lines[init_start].lstrip())
    for j in range(init_start + 1, len(lines)):
        line = lines[j]
        if line.strip() and len(line) - len(line.lstrip()) <= init_indent:
            # Check if it's another method or class
            if line.lstrip().startswith('def ') or line.lstrip().startswith('class ') or line.lstrip().startswith('@'):
                init_end = j
                break
    if init_end is None:
        init_end = len(lines)

    print(f"__init__ method spans lines {init_start+1} to {init_end}")

    # Let's see the current implementation
    print("\nCurrent implementation:")
    for j in range(init_start, init_end):
        print(f"{j+1}: {lines[j]}", end='')
else:
    print("Could not find __init__ method")
    sys.exit(1)
EOF

